sql:
SELECT SUM(confirmed_case_count) as total_cases
FROM covid_cases
WHERE zcta = '10001';

SELECT *
FROM demographics
WHERE zcta = '10001';

SELECT *
FROM covid_deaths
WHERE zcta = '10001';

SELECT zcta, AVG(capacity) AS average_capacity
FROM testing_sites
GROUP BY zcta;

SELECT AVG(death_count) AS average_death_count
FROM covid_deaths
WHERE zcta = '0' AND date = '0';
